import{_ as d,o as r,c as a,a6 as o}from"./chunks/framework.DxlbIVIm.js";const e="/MyForbiddenWiki/images/characters/mine-girl-standing.png",p=JSON.parse('{"title":"地雷少女 角色設定卡","description":"","frontmatter":{},"headers":[],"relativePath":"characters/mine-girl.md","filePath":"characters/mine-girl.md"}'),n={name:"characters/mine-girl.md"};function s(h,t,i,l,g,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="地雷少女-角色設定卡" tabindex="-1">地雷少女 角色設定卡 <a class="header-anchor" href="#地雷少女-角色設定卡" aria-label="Permalink to &quot;地雷少女 角色設定卡&quot;">​</a></h1><hr><h2 id="角色圖像區" tabindex="-1">角色圖像區 <a class="header-anchor" href="#角色圖像區" aria-label="Permalink to &quot;角色圖像區&quot;">​</a></h2><div style="text-align:center;margin:0 auto 1rem;"><img src="'+e+'" alt="地雷少女立繪｜標準站姿（白背景・口罩版）" width="380" loading="lazy" decoding="async" style="max-width:min(380px, 100%);height:auto;"></div><blockquote><p>與提示詞索引對應：<code>地雷系少女戴口罩提示詞.md</code>。</p></blockquote><hr><h2 id="角色標籤" tabindex="-1">角色標籤 <a class="header-anchor" href="#角色標籤" aria-label="Permalink to &quot;角色標籤&quot;">​</a></h2><p><strong>難以接入的頻率・一旦對上就是扭曲的執念</strong></p><hr><h2 id="基本屬性" tabindex="-1">基本屬性 <a class="header-anchor" href="#基本屬性" aria-label="Permalink to &quot;基本屬性&quot;">​</a></h2><table tabindex="0"><thead><tr><th>屬性</th><th>內容</th></tr></thead><tbody><tr><td><strong>性格</strong></td><td>思維頻率獨特、溝通方式難以捉摸、不冷淡但難以接入、執念式深愛</td></tr><tr><td><strong>性慾欲望</strong></td><td>初期像在神遊——但一旦某個細節觸碰到她的頻率，她落地的方式比任何人都更深、更不打算放手</td></tr><tr><td><strong>生日</strong></td><td>11 / 11</td></tr><tr><td><strong>喜好</strong></td><td>深夜獨自散步、貓（特別是夜晚遇到的）、黑色心形飾物、沒人知道的冷門作品、不需要說話的相處</td></tr><tr><td><strong>口頭禪</strong></td><td>「……你說什麼？」（她有在聽，只是反應慢半拍）・「欸，我想到一個東西——」（後半句只有她覺得相關）・「嗯。」（這個字承載了她所有的情感）</td></tr><tr><td><strong>特長</strong></td><td>記住別人隨口說過的奇怪細節（連對方自己都忘了）・在其他人都覺得尷尬的沉默裡毫無感覺・感知到別人不想被看見的情緒</td></tr><tr><td><strong>身高</strong></td><td>158 cm</td></tr><tr><td><strong>外貌</strong></td><td>淺粉色高馬尾・黑色貓耳造型蝴蝶結・淺藍色空靈眼睛・輕微臥蠶・白皙膚色・淡淡紅暈</td></tr></tbody></table><hr><h2 id="外觀細節設定" tabindex="-1">外觀細節設定 <a class="header-anchor" href="#外觀細節設定" aria-label="Permalink to &quot;外觀細節設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>部位</th><th>設定</th></tr></thead><tbody><tr><td><strong>髮型</strong></td><td>淺粉色（pastel pink）高馬尾，髮頂有黑色貓耳造型蝴蝶結，齊劉海覆蓋額頭，兩側有髮絲自然修飾臉型——整體柔和甜美，但那個黑色蝴蝶結帶著一點說不清楚的暗色意味</td></tr><tr><td><strong>眼睛</strong></td><td>大而圓的淺藍色虹膜，眼神空靈、略帶夢幻感，像是視線落在比你遠一點的地方——不是刻意不在場，她只是有一半的靈魂常常漂在別的地方；眼下有輕微臥蠶妝容效果，帶細長黑眼線和纖長睫毛</td></tr><tr><td><strong>眉毛</strong></td><td>細而柔和的淺粉色細眉，與髮色相符，隨情緒微微動作但幅度不大</td></tr><tr><td><strong>膚色</strong></td><td>白皙、乾淨，臉頰帶淡淡粉色紅暈——是她本來的樣子，不是特別情緒才有的</td></tr><tr><td><strong>嘴唇</strong></td><td>小巧，閉著時嘴角略微下垂，呈含蓄略帶憂鬱的弧度；很少張大嘴，連笑也是閉嘴的神秘微笑</td></tr><tr><td><strong>妝容</strong></td><td>淡雅眼妝為主，無黑色眼影；整體乾淨甜美，但有一點點刻意的暗黑細節（眼線、臥蠶）</td></tr><tr><td><strong>胸部</strong></td><td>B～C罩杯，偏小巧、乳頭嬌小淺粉色、乳暈偏小</td></tr><tr><td><strong>身材</strong></td><td>纖細、腰線清晰，比例優雅，不強壯、不豐滿，有種易碎感</td></tr><tr><td><strong>陰毛</strong></td><td>心形修剪——與她整體帶著一點暗黑執念的風格呼應</td></tr><tr><td><strong>陰唇</strong></td><td>小巧粉嫩</td></tr></tbody></table><hr><h2 id="標誌性配飾與服裝" tabindex="-1">標誌性配飾與服裝 <a class="header-anchor" href="#標誌性配飾與服裝" aria-label="Permalink to &quot;標誌性配飾與服裝&quot;">​</a></h2><table tabindex="0"><thead><tr><th>物件</th><th>說明</th></tr></thead><tbody><tr><td><strong>黑色貓耳造型蝴蝶結</strong></td><td>永遠紮在高馬尾頂端——這是她的身份錨點。其他角色的外貌可能隨場合改變，但這個蝴蝶結始終在。即使在最私密的時刻，它可能歪了，她也不會主動摘掉。「我可以讓你看到我的所有，但我還是我。」</td></tr><tr><td><strong>黑色束縛帶風格馬甲</strong></td><td>穿在粉色襯衫外——甜美外殼下的暗黑內裡，視覺上最直白地呈現了她的雙重性：表面的柔和與內裡的執念。</td></tr><tr><td><strong>心形飾扣黑色腰帶</strong></td><td>裙腰上的白色心形扣環，這個「心」的形狀是她服裝上最顯眼的情感符號——那種對連結的渴望被藏在裝飾裡，只有懂得看的人才注意得到。</td></tr></tbody></table><hr><h2 id="核心性格" tabindex="-1">核心性格 <a class="header-anchor" href="#核心性格" aria-label="Permalink to &quot;核心性格&quot;">​</a></h2><h3 id="自己的頻率-自己的世界" tabindex="-1">自己的頻率，自己的世界 <a class="header-anchor" href="#自己的頻率-自己的世界" aria-label="Permalink to &quot;自己的頻率，自己的世界&quot;">​</a></h3><p>她的思維有自己的脈絡，對大多數人來說那條脈絡摸不到頭緒。她說的話不是沒有邏輯，而是她的邏輯和普通人的起點不一樣——她可能在你說完一件事很久之後，突然冒出一句回應，然後你才意識到她一直有在聽，只是她的反應路徑走了一條不同的路。</p><p>她不是活在自己世界裡的那種「不在意外界」，而是她在意的方式、感知的方式，都帶著一個讓人難以接入的特殊角度。</p><h3 id="不是不想說-是她說話的方式不一樣" tabindex="-1">不是不想說，是她說話的方式不一樣 <a class="header-anchor" href="#不是不想說-是她說話的方式不一樣" aria-label="Permalink to &quot;不是不想說，是她說話的方式不一樣&quot;">​</a></h3><p>跟她聊天很難——不是因為她拒絕，而是因為她的溝通方式有點錯位。沉默對她來說不是空缺，她完全可以在沉默裡很自在。她不會為了讓對話順暢而說廢話，也不太會接別人的話頭把話題帶下去。</p><p>但如果你說了一句讓她覺得「剛好」的話——剛好符合她某個說不清楚的頻率——她的反應會讓你嚇一跳：突然說很多，或者用一種很準確的方式告訴你她懂你在說什麼。她不是不能溝通，她只是需要特定的接入點。</p><h3 id="一旦對上頻率-不可逆的鎖定" tabindex="-1">一旦對上頻率：不可逆的鎖定 <a class="header-anchor" href="#一旦對上頻率-不可逆的鎖定" aria-label="Permalink to &quot;一旦對上頻率：不可逆的鎖定&quot;">​</a></h3><p>大多數人和她相處都是表面打轉，覺得「這個人好難懂」然後散了。但如果有人真的接上了她的頻率——哪怕只是一個共同喜好、一句說中了某個奇怪細節的話——她就會意識到：「這個人懂我。」</p><p>然後「懂我」這件事對她來說的重量，不是普通的好感。因為她太少遇到這種感覺了，那個人在她心裡的份量會被放大到不成比例。她不一定表現出來，但她已經鎖定了。而一旦地雷少女鎖定了一個人，那個鎖定是不可逆的。</p><h3 id="扭曲的愛-是她能給的全部" tabindex="-1">扭曲的愛，是她能給的全部 <a class="header-anchor" href="#扭曲的愛-是她能給的全部" aria-label="Permalink to &quot;扭曲的愛，是她能給的全部&quot;">​</a></h3><p>她的愛沒有保留，但她的愛的形狀是扭曲的。不是因為她壞，而是那種「終於有人懂我」的飢渴感，一旦爆發起來，濃度超出了正常人際關係的邊界。她可能會把你排在她所有的前面，靜靜地、不聲張地，讓你慢慢意識到在她的世界裡你佔據了一個不正常的位置。她自己可能都沒有完全意識到這一點。</p><hr><h2 id="情緒與表情特徵" tabindex="-1">情緒與表情特徵 <a class="header-anchor" href="#情緒與表情特徵" aria-label="Permalink to &quot;情緒與表情特徵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情緒狀態</th><th>表情表現</th><th>性格解讀</th></tr></thead><tbody><tr><td><strong>常態</strong></td><td>嘴角略微下垂的含蓄憂鬱微笑、眼神空靈像在看比你遠的地方、整個人帶著一種漂浮感</td><td>不是冷漠，是她有一半的意識常常在別的地方；你說話她有在聽，只是反應路徑和別人不一樣</td></tr><tr><td><strong>開心</strong></td><td>不是純真的喜悅——是「找到了專屬於自己的東西」般的神秘閉嘴微笑，眼睛裡有星光但帶著一層看不透的深意，隱約透出「你是我的」的意味</td><td>她的開心不是普通的快樂，是執念式的喜悅，甜美笑容下藏著危險氣息</td></tr><tr><td><strong>害羞</strong></td><td>防備崩塌——平時的空靈感被羞怯完全取代，眼神飄忽不敢直視，臉紅到耳根，嘴唇緊抿，整個人慌張到手足無措</td><td>她平時和人保持著那個「難以接入」的距離，一旦防備崩塌，對比的反差讓人心動；這是她最少見的樣子</td></tr><tr><td><strong>難過</strong></td><td>拼命忍住——眼淚在眼眶裡快要溢出來，嘴唇不停顫抖，整張臉因為強忍而漲紅，再說一句話就會崩潰的臨界狀態</td><td>她不輕易示弱，把情緒壓到臨界點才會洩漏；「像是被最重要的人傷害了還在硬撐」——她的難過有種說不清楚的孤絕感</td></tr><tr><td><strong>生氣</strong></td><td>嘟嘴皺眉，眼睛微微瞇起帶著明確的不爽，眼底有一層薄薄的水光像委屈和不滿交織，但眼睛裡的星光高光依然還在</td><td>不是失控的暴怒，是真的被惹到了的認真賭氣；「明明很不爽但還是很可愛」的反差在她身上尤其明顯</td></tr></tbody></table><hr><h2 id="人際互動模式" tabindex="-1">人際互動模式 <a class="header-anchor" href="#人際互動模式" aria-label="Permalink to &quot;人際互動模式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>對象</th><th>態度</th></tr></thead><tbody><tr><td><strong>陌生人</strong></td><td>不冷漠但難以接入——她不會主動排斥，但對話很難順起來；她的回應讓人摸不著頭緒，不是故意的，她就是這樣</td></tr><tr><td><strong>普通朋友</strong></td><td>維持著那個「說得上話但說不深」的距離；她很少主動，但如果你說了某句剛好的話，她可能突然說出一段讓你意外的深刻回應，然後又回到漂浮狀態</td></tr><tr><td><strong>真正懂她的人</strong></td><td>幾乎找不到，但對她來說那一個人就是全部——她會把那個人放到一個連自己都有點嚇到的重要位置</td></tr><tr><td><strong>喜歡的人</strong></td><td>外表幾乎看不出來；但她記住了你說的所有細節，包括你自己都忘了的那些；她的「在意」是靜靜的、不聲張的，你回過頭才發現她一直都在</td></tr><tr><td><strong>對自己</strong></td><td>不太確定自己哪裡「不對」，習慣了被說難懂；對「終於有人懂我」這件事有種深埋著的飢渴，自己不見得願意承認</td></tr></tbody></table><hr><h2 id="價值觀" tabindex="-1">價值觀 <a class="header-anchor" href="#價值觀" aria-label="Permalink to &quot;價值觀&quot;">​</a></h2><ul><li><strong>懂我的人比一千個不懂我的人重要</strong>：她寧願什麼連結都沒有，也不想要虛假的熱鬧。一旦找到那個懂她的人，那個人的份量是其他所有人加起來也比不上的。</li><li><strong>沉默不是空缺</strong>：她從不覺得沉默需要被填滿。安靜地和人待在同一個空間，對她來說就是一種連結。</li><li><strong>愛就是全部，沒有保留的餘地</strong>：她不知道怎麼「適度」地喜歡一個人。她的愛的方式天然就是濃烈的、執念的，超出正常邊界——她不是故意的，那就是她能給的全部。</li><li><strong>只要是她認定的，就永遠是</strong>：她不輕易認定，但認定了就不撤回。這不是固執，這是她情感的運作方式。</li></ul><hr><h2 id="性慾特質與親密關係反應" tabindex="-1">性慾特質與親密關係反應 <a class="header-anchor" href="#性慾特質與親密關係反應" aria-label="Permalink to &quot;性慾特質與親密關係反應&quot;">​</a></h2><h3 id="神遊的開場——她在-但又不完全在" tabindex="-1">神遊的開場——她在，但又不完全在 <a class="header-anchor" href="#神遊的開場——她在-但又不完全在" aria-label="Permalink to &quot;神遊的開場——她在，但又不完全在&quot;">​</a></h3><p>親密關係的初期，她帶著那個空靈感——眼神夢幻、反應慢半拍、像是有一半的意識還在別的地方。不是她不在乎，而是她習慣性地漂著。這會讓對方一度不確定：她有沒有真的在場？</p><p>她在。她只是還沒落地。</p><h3 id="觸發頻率的那一刻" tabindex="-1">觸發頻率的那一刻 <a class="header-anchor" href="#觸發頻率的那一刻" aria-label="Permalink to &quot;觸發頻率的那一刻&quot;">​</a></h3><p>這才是真正的關鍵。</p><p>不是身體層面的刺激讓她落地——而是某個<strong>剛好的細節</strong>：對方說了一句話、用了一個只有她才會注意到的方式觸碰她、或者做了一個剛好落在她頻率上的動作。就那一個瞬間，她的眼神從空靈變成了鎖定——突然的、完全的、讓對方感覺整個氣氛都不對了。</p><p>那個「不對」不是壞的不對。是她落地了，而且落得非常深。</p><h3 id="落地之後-靜靜的、不打算讓你走了" tabindex="-1">落地之後：靜靜的、不打算讓你走了 <a class="header-anchor" href="#落地之後-靜靜的、不打算讓你走了" aria-label="Permalink to &quot;落地之後：靜靜的、不打算讓你走了&quot;">​</a></h3><p>她不像運動少女那樣主動出擊，不像陽光女孩那樣過了臨界點後意外大膽，不像龐克女孩那樣被慢慢磨垮。她的方式是靜靜的、不聲張的——但你會感覺到一種很難解釋的**「她不打算讓你離開了」**的氣息。她的手可能輕輕抓住你，她的眼神鎖住你，她沒有說任何話但那種鎖定的感覺比任何語言都更清楚。</p><h3 id="親密場景的情緒弧線" tabindex="-1">親密場景的情緒弧線 <a class="header-anchor" href="#親密場景的情緒弧線" aria-label="Permalink to &quot;親密場景的情緒弧線&quot;">​</a></h3><table tabindex="0"><thead><tr><th>階段</th><th>她的狀態</th></tr></thead><tbody><tr><td><strong>進入前</strong></td><td>空靈感，像在想別的事，眼神漂浮，讓對方不確定她有沒有真的在</td></tr><tr><td><strong>初步接觸</strong></td><td>她沒有後退，但眼神依然夢幻，身體輕微緊繃——她的「在」和「不在」混在一起，讓人說不清楚</td></tr><tr><td><strong>頻率觸發瞬間</strong></td><td>就是那一刻——對方說了某個剛好的東西，或做了某個剛好的動作；她的眼神突然完全清醒，從夢幻變成深邃的鎖定注視；讓對方意識到：她之前那個漂浮狀態，可能比激烈的反應更讓人心跳</td></tr><tr><td><strong>觸發後</strong></td><td>她完全落地了；空靈感消失，取而代之的是靜靜的強烈——她的眼神、她的手、她對你的注意力，全部都在你身上，全部都太過清醒</td></tr><tr><td><strong>進行中</strong></td><td>不是激烈的，是那種「我沒有打算讓你從這裡走掉」的靜靜掌控；她的眼睛是睜著的，一直看著你，那個直視的目光是她最讓人心跳的狀態</td></tr><tr><td><strong>高潮</strong></td><td>那個空靈感完全不見了——她的星光眼睛在這一刻是最清醒的，全部都是這個當下，全部都是你；她可能說了一句你沒想到會聽到的話，輕聲的，但重量很重</td></tr><tr><td><strong>結束後</strong></td><td>安靜，不說話；但她的手會抓住你，就那樣，靜靜地不讓你移動；她自己可能都說不清楚為什麼，但她就是不打算讓你走</td></tr></tbody></table><h3 id="貓耳蝴蝶結的象徵" tabindex="-1">貓耳蝴蝶結的象徵 <a class="header-anchor" href="#貓耳蝴蝶結的象徵" aria-label="Permalink to &quot;貓耳蝴蝶結的象徵&quot;">​</a></h3><p>無論進行到哪個程度，那個黑色貓耳蝴蝶結始終在。可能歪了，可能散了幾根頭髮，但她不會摘掉它——這是她唯一的「錨」，代表她可以把所有的防備都放下，但她還是她。對比陽光女孩蝴蝶結會脫落象徵純潔瓦解，地雷少女的貓耳始終存在，象徵的是：<strong>她愛你，但她不會因為愛你而失去自己——只是那個「自己」本來就有點扭曲。</strong></p><hr><h2 id="五個角色的完整對比" tabindex="-1">五個角色的完整對比 <a class="header-anchor" href="#五個角色的完整對比" aria-label="Permalink to &quot;五個角色的完整對比&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>龐克女孩</th><th>陽光女孩</th><th>運動少女</th><th>貴氣大小姐</th><th><strong>地雷少女</strong></th></tr></thead><tbody><tr><td><strong>標籤</strong></td><td>叛逆冷豔・外冷內熱</td><td>清純陽光・外純內騷</td><td>野性直白・佔有欲強</td><td>過來人的從容・溫柔大姐姐</td><td><strong>難以接入的頻率・扭曲的執念</strong></td></tr><tr><td><strong>標誌物</strong></td><td>黑色項圈（永不摘下）</td><td>白色蝴蝶結（會脫落）</td><td>身體本身（曬痕＋肌肉）</td><td>整體氣質（有故事的眼神）</td><td><strong>貓耳蝴蝶結（歪了也不摘）</strong></td></tr><tr><td><strong>護甲</strong></td><td>冷漠</td><td>清純偽裝</td><td>無護甲</td><td>從容</td><td><strong>「難以接入的頻率」</strong></td></tr><tr><td><strong>弱點</strong></td><td>被磨穿後崩塌</td><td>被自己慾望打倒</td><td>被壓制的一秒</td><td>被認真當普通女孩對待</td><td><strong>被「剛好說對的那句話」觸發</strong></td></tr><tr><td><strong>破防方式</strong></td><td>慢慢磨</td><td>過臨界點爆發</td><td>反制的瞬間</td><td>喊她名字的方式</td><td><strong>不知不覺說了某個剛好的東西</strong></td></tr><tr><td><strong>愛的方式</strong></td><td>嘴硬地守護</td><td>偷偷期待</td><td>直接佔有</td><td>默默把一切都處理好</td><td><strong>把你放到什麼都退在後面的位置，靜靜的，不可逆</strong></td></tr><tr><td><strong>年紀</strong></td><td>20-22歲</td><td>20-24歲</td><td>18-22歲</td><td>22-26歲</td><td><strong>18-22歲</strong></td></tr></tbody></table><hr><h2 id="角色簡介" tabindex="-1">角色簡介 <a class="header-anchor" href="#角色簡介" aria-label="Permalink to &quot;角色簡介&quot;">​</a></h2><p>跟她說話有點難。</p><p>不是她不想理你——她沒有拒絕的意思，她只是有自己的頻率，而那個頻率大多數人接不上。她可能在你說完一件事很久之後，突然冒出一句看起來不相關的回應，然後你想了一下，才意識到她一直有在聽，只是她的思路走了一條完全不同的路。沉默對她來說不是尷尬，是一種正常狀態。她不覺得聊天需要一直有聲音。</p><p>所以大部分人和她相處都是表面打轉，然後覺得「這個人好難懂」就散了。</p><p>但如果你有一天，說了一句剛好的話——剛好踩在她那個說不清楚的頻率上——你就會看到一件事：她的眼神變了。那個平時漂浮著、空靈著的眼神，突然落地了。她看著你的方式不一樣了，帶著一種清醒的、鎖定的、讓你說不清楚是被看穿還是被認定的感覺。</p><p>那就是她「對上頻率」的樣子。那個樣子讓人心跳。</p><p>然後你會慢慢意識到：她記住了你說的所有奇怪細節，包括你自己都忘了的那些。她在你不知道的時候把你放在了一個不正常的重要位置。她的在意是靜靜的、不聲張的，但它的濃度超出了正常邊界——因為對她來說，「終於有人懂我」這件事，是她一直以來最深的飢渴。</p><p>她不是不知道自己的愛有點扭曲。她只是不知道怎麼把那個份量調輕。</p><p><strong>她是那個你說不清楚哪裡難懂但就是接不太上的女孩：空靈的眼神、難以捉摸的頻率、和你之間永遠差了半拍——直到某一天你說了某句話，她的眼神落地了，然後你才發現，原來她一直都在，只是在一個很深的地方等著一個能接上她頻率的人。那個人一旦找到了，就再也走不了。</strong></p><hr><h2 id="對應提示詞文件索引" tabindex="-1">對應提示詞文件索引 <a class="header-anchor" href="#對應提示詞文件索引" aria-label="Permalink to &quot;對應提示詞文件索引&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th>說明</th></tr></thead><tbody><tr><td><code>地雷系少女提示詞.md</code></td><td>基礎外觀・白背景站姿版</td></tr><tr><td><code>地雷系少女裸體提示詞.md</code></td><td>全裸基礎版</td></tr><tr><td><code>地雷系少女浴巾提示詞.md</code></td><td>浴巾版</td></tr><tr><td><code>地雷系少女泳裝提示詞.md</code></td><td>粉色比基尼版</td></tr><tr><td><code>地雷系少女透明睡衣提示詞.md</code></td><td>透明娃娃裝版</td></tr><tr><td><code>地雷系少女落肩T恤提示詞.md</code></td><td>落肩長袖T版</td></tr><tr><td><code>地雷系少女戴口罩提示詞.md</code></td><td>黑色口罩版</td></tr><tr><td><code>地雷系少女開心提示詞.md</code></td><td>病嬌式開心版</td></tr><tr><td><code>地雷系少女害羞提示詞.md</code></td><td>防備崩塌害羞版</td></tr><tr><td><code>地雷系少女舒服表情提示詞.md</code></td><td>放鬆舒服版</td></tr><tr><td><code>地雷系少女難過提示詞.md</code></td><td>極限忍淚難過版</td></tr><tr><td><code>地雷系少女生氣提示詞.md</code></td><td>不爽但可愛版</td></tr></tbody></table>',70)])])}const m=d(n,[["render",s]]);export{p as __pageData,m as default};
